import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './mentordashboard.css';

function MentorDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [mentorData, setMentorData] = useState(null);
  const [assignedStudents, setAssignedStudents] = useState([]);
  const [availabilitySlots, setAvailabilitySlots] = useState([]);
  const [specialties, setSpecialties] = useState([]);
  const [newSpecialty, setNewSpecialty] = useState('');
  const [editMode, setEditMode] = useState(false);
  const [editingSpecialty, setEditingSpecialty] = useState(null);
  const [studentProjects, setStudentProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mySlots, setMySlots] = useState([]);
  const [mentorRequests, setMentorRequests] = useState([]);
  const [newSlotDay, setNewSlotDay] = useState('');
  const [newSlotStart, setNewSlotStart] = useState('');
  const [newSlotEnd, setNewSlotEnd] = useState('');
  const [newSlotLocation, setNewSlotLocation] = useState('');
  const [slotStudentNames, setSlotStudentNames] = useState({});

  // Fetch mentor data and assigned students
  useEffect(() => {
    const fetchMentorData = async () => {
      try {
        const user = auth.currentUser;
        if (!user) {
          navigate('/');
          return;
        }

        // Fetch mentor's data
        const mentorDoc = await getDoc(doc(db, "users", user.uid));
        if (!mentorDoc.exists()) {
          alert("Mentor profile not found");
          navigate('/');
          return;
        }

        const mentorData = mentorDoc.data();
        setMentorData(mentorData);

        // Initialize available slots if not set
        if (mentorData.availableSlots === undefined) {
          await updateDoc(doc(db, "users", user.uid), {
            availableSlots: 7,
            assignedStudents: []
          });
          setAvailabilitySlots(7);
          setMentorData(prev => ({ ...prev, availableSlots: 7 }));
        } else {
          setAvailabilitySlots(mentorData.availableSlots);
        }

        // Fetch assigned students
        const studentsQuery = query(
          collection(db, "users"),
          where("mentorId", "==", user.uid)
        );
        const studentsSnapshot = await getDocs(studentsQuery);
        const students = studentsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setAssignedStudents(students);

        // Fetch specialties
        if (mentorData.specialties) {
          setSpecialties(mentorData.specialties);
        }

        // Fetch projects for assigned students
        const projectsQuery = query(
          collection(db, "projects"),
          where("mentorId", "==", user.uid)
        );
        const projectsSnapshot = await getDocs(projectsQuery);
        const projects = projectsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setStudentProjects(projects);

      } catch (error) {
        console.error("Error fetching mentor data:", error);
        alert("Error loading dashboard. Please try again.");
      } finally {
        setLoading(false);
      }
    };

    fetchMentorData();
  }, [navigate]);

  // Add a real-time listener for mentor data changes
  useEffect(() => {
    const user = auth.currentUser;
    if (!user) return;

    const mentorRef = doc(db, "users", user.uid);
    const unsubscribe = onSnapshot(mentorRef, (doc) => {
      if (doc.exists()) {
        const data = doc.data();
        setMentorData(data);
        setAvailabilitySlots(data.availableSlots || 0);
        setAssignedStudents(data.assignedStudents || []);
      }
    });

    return () => unsubscribe();
  }, []);

  // Fetch own slots in real time
  useEffect(() => {
    const user = auth.currentUser;
    if (!user) return;
    const q = query(collection(db, 'availability'), where('mentorId', '==', user.uid));
    const unsub = onSnapshot(q, (snap) => {
      setMySlots(snap.docs.map(doc => ({ id: doc.id, ...doc.data() })));
    });
    return unsub;
  }, []);

  // subscribe to incoming requests
  useEffect(() => {
    const user = auth.currentUser;
    if (!user) return;
    const rq = query(
      collection(db, 'mentorRequests'), 
      where('mentorId', '==', user.uid),
      where('status', '==', 'pending')
    );
    const unsub = onSnapshot(rq, (snap) => {
      setMentorRequests(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    return unsub;
  }, []);

  // whenever mySlots change, resolve student names for booked slots
  useEffect(() => {
    const loadNames = async () => {
      const pendingIds = (mySlots || [])
        .filter(s => s.status === 'booked' && s.studentId)
        .map(s => s.studentId)
        .filter(id => id && !slotStudentNames[id]);
      for (const id of pendingIds) {
        try {
          const snap = await getDoc(doc(db, 'users', id));
          if (snap.exists()) {
            const name = snap.data()?.name || id;
            setSlotStudentNames(prev => ({ ...prev, [id]: name }));
          } else {
            setSlotStudentNames(prev => ({ ...prev, [id]: id }));
          }
        } catch (e) {
          setSlotStudentNames(prev => ({ ...prev, [id]: id }));
        }
      }
    };
    loadNames();
  }, [mySlots]);

  const handleLogout = async () => {
    try {
      await signOut(auth);
      navigate('/');
    } catch (error) {
      console.error('Error logging out:', error);
    }
  };

  const updateAvailability = async (day, startTime, endTime, slotId = null, location = '') => {
    try {
      const user = auth.currentUser;
      if (!user) return;

      const slotData = {
        mentorId: user.uid,
        day,
        startTime,
        endTime,
        mode: 'offline',
        location: location || '',
        updatedAt: serverTimestamp()
      };

      if (slotId) {
        // Update existing slot
        await updateDoc(doc(db, "availability", slotId), slotData);
      } else {
        // Create new slot, default status free
        await addDoc(collection(db, "availability"), { ...slotData, status: 'free' });
      }

      // Refresh availability slots
      const availabilityQuery = query(
        collection(db, "availability"),
        where("mentorId", "==", user.uid)
      );

      const availabilitySnapshot = await getDocs(availabilityQuery);
      const slots = availabilitySnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));

      setMySlots(slots);
    } catch (error) {
      console.error("Error updating availability:", error);
    }
  };

  const handleReportReview = async (studentId, reportId, status, feedback) => {
    try {
      await updateDoc(doc(db, "reports", reportId), {
        status,
        feedback,
        reviewedAt: serverTimestamp()
      });

      // Refresh data
      const updatedStudents = [...assignedStudents];
      const studentIndex = updatedStudents.findIndex(student => student.id === studentId);

      if (studentIndex !== -1) {
        const reportIndex = updatedStudents[studentIndex].reports.findIndex(
          report => report.id === reportId
        );

        if (reportIndex !== -1) {
          updatedStudents[studentIndex].reports[reportIndex].status = status;
          updatedStudents[studentIndex].reports[reportIndex].feedback = feedback;
          updatedStudents[studentIndex].reports[reportIndex].reviewedAt = new Date();

          setAssignedStudents(updatedStudents);
        }
      }
    } catch (error) {
      console.error("Error reviewing report:", error);
    }
  };

  const handleProjectStatus = async (projectId, status) => {
    try {
      const user = auth.currentUser;
      if (!user) {
        alert('Please log in to perform this action');
        return;
      }

      const projectRef = doc(db, "projects", projectId);
      const projectDoc = await getDoc(projectRef);

      if (!projectDoc.exists()) {
        alert('Project not found');
        return;
      }

      const projectData = projectDoc.data();

      // Update project status
      await updateDoc(projectRef, {
        status,
        lastUpdated: serverTimestamp()
      });

      if (status === 'approved') {
        // Get student data
        const studentRef = doc(db, "users", projectData.studentId);
        const studentDoc = await getDoc(studentRef);

        if (!studentDoc.exists()) {
          alert('Student not found');
          return;
        }

        const studentData = studentDoc.data();

        // Create new student object
        const newStudent = {
          id: projectData.studentId,
          name: studentData.name,
          email: studentData.email,
          projectId: projectId,
          projectTitle: projectData.title,
          reports: []
        };

        // Update mentor's document
        const mentorRef = doc(db, "users", user.uid);
        const mentorDoc = await getDoc(mentorRef);
        const currentSlots = mentorDoc.data().availableSlots || 0;

        if (currentSlots <= 0) {
          alert('No available slots left');
          return;
        }

        await updateDoc(mentorRef, {
          assignedStudents: arrayUnion(newStudent),
          availableSlots: increment(-1)
        });

        // Update student's document
        await updateDoc(studentRef, {
          mentorId: user.uid
        });

        // Update local state
        setAssignedStudents(prev => [...prev, newStudent]);
        setMentorData(prev => ({
          ...prev,
          availableSlots: currentSlots - 1
        }));
      } else if (status === 'rejected') {
        const mentorRef = doc(db, "users", user.uid);
        const mentorDoc = await getDoc(mentorRef);
        const currentStudents = mentorDoc.data().assignedStudents || [];

        const updatedStudents = currentStudents.filter(
          student => student.id !== projectData.studentId
        );

        await updateDoc(mentorRef, {
          assignedStudents: updatedStudents,
          availableSlots: increment(1)
        });

        const studentRef = doc(db, "users", projectData.studentId);
        await updateDoc(studentRef, {
          mentorId: null
        });

        setAssignedStudents(updatedStudents);
        setMentorData(prev => ({
          ...prev,
          availableSlots: (prev.availableSlots || 0) + 1
        }));
      }

      // Refresh projects list
      const projectsQuery = query(
        collection(db, "projects"),
        where("mentorId", "==", user.uid)
      );
      const projectsSnapshot = await getDocs(projectsQuery);
      const updatedProjects = projectsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setStudentProjects(updatedProjects);

    } catch (error) {
      console.error("Error updating project status:", error);
      alert("Error updating project status. Please try again.");
    }
  };

  const handleAddSpecialty = async () => {
    if (!newSpecialty.trim()) {
      alert('Please enter a specialty');
      return;
    }

    try {
      const user = auth.currentUser;
      if (!user) {
        alert('Please log in to add specialties');
        return;
      }

      const updatedSpecialties = [...specialties, newSpecialty.trim()];

      await updateDoc(doc(db, "users", user.uid), {
        specialties: updatedSpecialties
      });

      setSpecialties(updatedSpecialties);
      setNewSpecialty('');
    } catch (error) {
      console.error("Error adding specialty:", error);
      alert("Error adding specialty. Please try again.");
    }
  };

  const handleDeleteSpecialty = async (index) => {
    try {
      const user = auth.currentUser;
      if (!user) {
        alert('Please log in to delete specialties');
        return;
      }

      const updatedSpecialties = specialties.filter((_, i) => i !== index);

      await updateDoc(doc(db, "users", user.uid), {
        specialties: updatedSpecialties
      });

      setSpecialties(updatedSpecialties);
    } catch (error) {
      console.error("Error deleting specialty:", error);
      alert("Error deleting specialty. Please try again.");
    }
  };

  const handleSaveSpecialty = async (index) => {
    if (!editingSpecialty.trim()) {
      alert('Please enter a specialty');
      return;
    }

    try {
      const user = auth.currentUser;
      if (!user) {
        alert('Please log in to edit specialties');
        return;
      }

      const updatedSpecialties = [...specialties];
      updatedSpecialties[index] = editingSpecialty.trim();

      await updateDoc(doc(db, "users", user.uid), {
        specialties: updatedSpecialties
      });

      setSpecialties(updatedSpecialties);
      setEditMode(false);
      setEditingSpecialty(null);
    } catch (error) {
      console.error("Error saving specialty:", error);
      alert("Error saving specialty. Please try again.");
    }
  };

  async function acceptRequest(req) {
    try {
      const user = auth.currentUser; if (!user) return;
      // Resolve project title
      let resolvedProjectTitle = req.projectTitle || '';
      if (!resolvedProjectTitle && req.projectId) {
        const pSnap = await getDoc(doc(db, 'projects', req.projectId));
        if (pSnap.exists()) {
          resolvedProjectTitle = pSnap.data()?.title || '';
        }
      }

      // Update student record
      const studentRef = doc(db, 'users', req.studentId);
      await updateDoc(studentRef, { mentorId: user.uid });

      // Update mentor slots and assigned list
      const mentorRef = doc(db, 'users', user.uid);
      const mentorSnap = await getDoc(mentorRef);
      const currentSlots = mentorSnap.data()?.availableSlots || 0;
      if (currentSlots <= 0) { alert('No available slots left'); return; }

      const newStudent = { 
        id: req.studentId, 
        name: req.studentName || '', 
        email: req.studentEmail || '',
        projectId: req.projectId || '',
        projectTitle: resolvedProjectTitle
      };

      await updateDoc(mentorRef, { 
        availableSlots: increment(-1), 
        assignedStudents: arrayUnion(newStudent) 
      });

      // Update request status
      await updateDoc(doc(db, 'mentorRequests', req.id), { status: 'accepted' });

      // Update project with mentor assignment
      if (req.projectId) {
        await updateDoc(doc(db, 'projects', req.projectId), { mentorId: user.uid, lastUpdated: serverTimestamp() });
      }
      alert('Request accepted');
    } catch (e) {
      console.error(e); alert('Failed to accept request');
    }
  }

  async function rejectRequest(req) {
    try {
      await updateDoc(doc(db, 'mentorRequests', req.id), { status: 'rejected' });
      alert('Request rejected');
    } catch (e) { console.error(e); alert('Failed to reject'); }
  }

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="mentor-dashboard">
      <div className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button onClick={handleLogout}>Logout</button>
      </div>

      <div className="tabs">
        <button 
          className={activeTab === 'dashboard' ? 'active' : ''}
          onClick={() => setActiveTab('dashboard')}
        >
          Dashboard
        </button>
        <button 
          className={activeTab === 'students' ? 'active' : ''}
          onClick={() => setActiveTab('students')}
        >
          Students
        </button>
        <button 
          className={activeTab === 'submissions' ? 'active' : ''}
          onClick={() => setActiveTab('submissions')}
        >
          Submissions
        </button>
        <button 
          className={activeTab === 'availability' ? 'active' : ''}
          onClick={() => setActiveTab('availability')}
        >
          Availability
        </button>
        <button 
          className={activeTab === 'specialties' ? 'active' : ''}
          onClick={() => setActiveTab('specialties')}
        >
          Specialties
        </button>
      </div>

      <div className="main-content">
        {activeTab === 'dashboard' && (
          <div className="dashboard-section">
            <h2>Welcome, {mentorData?.name}</h2>
            <div className="stats">
              <div className="stat-card">
                <h3>Assigned Students</h3>
                <p>{assignedStudents.length}/7</p>
              </div>
              <div className="stat-card">
                <h3>Available Slots</h3>
                <p>{mentorData?.availableSlots || 0}</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'students' && (
          <div className="students-section">
            <h2>Assigned Students ({assignedStudents.length}/7)</h2>
            {assignedStudents.length === 0 ? (
              <p>No students assigned yet.</p>
            ) : (
              <div className="student-cards">
                {assignedStudents.map(student => (
                  <div className="student-card" key={student.id}>
                    <h3>{student.name}</h3>
                    <p><strong>Email:</strong> {student.email}</p>
                    <p><strong>Project:</strong> {studentProjects.find(p => p.studentId === student.id)?.title || 'N/A'}</p>
                    <p>
                      <strong>Reports:</strong> {student.reports?.length || 0}
                    </p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'submissions' && (
          <div className="projects-section">
            <h2>Submissions</h2>
            <h3>Pending Requests</h3>
            {mentorRequests.length === 0 ? (
              <p>No pending requests.</p>
            ) : (
              <div className="project-cards">
                {mentorRequests.map(r => (
                  <div className="project-card" key={r.id}>
                    <h3>{r.projectTitle || 'Untitled Project'}</h3>
                    <p><strong>Student:</strong> {r.studentName} ({r.studentEmail})</p>
                    <p><strong>Status:</strong> {r.status}</p>
                    {r.status === 'pending' && (
                      <div className="project-actions">
                        <button className="approve-btn" onClick={()=>acceptRequest(r)}>Accept</button>
                        <button className="reject-btn" onClick={()=>rejectRequest(r)}>Reject</button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}

            <h3 style={{marginTop:20}}>Approved Projects</h3>
            {studentProjects.length === 0 ? (
              <p>No approved projects.</p>
            ) : (
              <div className="project-cards">
                {studentProjects.map(project => (
                  <div className="project-card" key={project.id}>
                    <h3>{project.title}</h3>
                    <p><strong>Status:</strong> {project.status}</p>
                    <p><strong>Description:</strong> {project.description}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'availability' && (
          <div className="availability-section">
            <h2>Your Meeting Slots</h2>

            <div className="add-slot" style={{background:'#fff',padding:16,border:'1px solid #e0e0e0',borderRadius:8,marginBottom:16}}>
              <h3 style={{marginTop:0}}>Add Offline Slot</h3>
              <div style={{display:'flex',gap:12,flexWrap:'wrap'}}>
                <div>
                  <label>Date</label><br/>
                  <input type="date" value={newSlotDay} onChange={(e)=>setNewSlotDay(e.target.value)} />
                </div>
                <div>
                  <label>Start</label><br/>
                  <input type="time" value={newSlotStart} onChange={(e)=>setNewSlotStart(e.target.value)} />
                </div>
                <div>
                  <label>End</label><br/>
                  <input type="time" value={newSlotEnd} onChange={(e)=>setNewSlotEnd(e.target.value)} />
                </div>
                <div>
                  <label>Location</label><br/>
                  <input type="text" placeholder="e.g., Lab 3, Block A" value={newSlotLocation} onChange={(e)=>setNewSlotLocation(e.target.value)} />
                </div>
                <div style={{alignSelf:'flex-end'}}>
                  <button 
                    className="approve-btn" 
                    onClick={async()=>{
                      if (!newSlotDay || !newSlotStart || !newSlotEnd) { alert('Please fill date and time'); return; }
                      await updateAvailability(newSlotDay, newSlotStart, newSlotEnd, null, newSlotLocation);
                      setNewSlotDay(''); setNewSlotStart(''); setNewSlotEnd(''); setNewSlotLocation('');
                    }}
                  >Add Slot</button>
                </div>
              </div>
            </div>

            <div className="slot-grid">
              {mySlots.length === 0 ? (<p>No slots added.</p>) : (
                mySlots.map(slot => (
                  <div className={`slot-card ${slot.status}`} key={slot.id}>
                    <p><b>{slot.day}</b> {slot.startTime}-{slot.endTime}</p>
                    {slot.location && <p><strong>Location:</strong> {slot.location}</p>}
                    {slot.status === 'booked' ? (
                      <span style={{color:'#FF6B00'}}>Booked by {slot.studentId ? (slotStudentNames[slot.studentId] || slot.studentId) : 'unknown'}</span>
                    ) : <span style={{color:'#4caf50'}}>Free</span>}
                  </div>
                ))
              )}
            </div>
          </div>
        )}

        {activeTab === 'specialties' && (
          <div className="specialties-section">
            <h2>Manage Specialties</h2>
            <div className="specialties-container">
              <div className="add-specialty-form">
                <input
                  type="text"
                  value={newSpecialty}
                  onChange={(e) => setNewSpecialty(e.target.value)}
                  placeholder="Enter a new specialty"
                  className="specialty-input"
                />
                <button 
                  onClick={handleAddSpecialty}
                  className="add-specialty-btn"
                  disabled={!newSpecialty.trim()}
                >
                  Add Specialty
                </button>
              </div>

              <div className="specialties-list">
                {specialties.length === 0 ? (
                  <p>No specialties added yet.</p>
                ) : (
                  specialties.map((specialty, index) => (
                    <div key={index} className="specialty-item">
                      {editMode && editingSpecialty === index ? (
                        <div className="edit-specialty-form">
                          <input
                            type="text"
                            value={editingSpecialty}
                            onChange={(e) => setEditingSpecialty(e.target.value)}
                            className="edit-specialty-input"
                          />
                          <div className="edit-actions">
                            <button 
                              onClick={() => handleSaveSpecialty(index)}
                              className="save-btn"
                              disabled={!editingSpecialty.trim()}
                            >
                              Save
                            </button>
                            <button 
                              onClick={() => {
                                setEditMode(false);
                                setEditingSpecialty(null);
                              }}
                              className="cancel-btn"
                            >
                              Cancel
                            </button>
                          </div>
                        </div>
                      ) : (
                        <div className="specialty-content">
                          <span className="specialty-text">{specialty}</span>
                          <div className="specialty-actions">
                            <button 
                              onClick={() => {
                                setEditMode(true);
                                setEditingSpecialty(specialty);
                              }}
                              className="edit-btn"
                            >
                              Edit
                            </button>
                            <button 
                              onClick={() => handleDeleteSpecialty(index)}
                              className="delete-btn"
                            >
                              Delete
                            </button>
                          </div>
                        </div>
                      )}
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default MentorDashboard;
